-- F26 Team scouting: versioned calibration, departments, assignments, observations, reports.
CREATE TABLE "ScoutingPreset" ("id" TEXT NOT NULL PRIMARY KEY, "name" TEXT NOT NULL, "description" TEXT, "isSystem" BOOLEAN NOT NULL DEFAULT false, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" DATETIME NOT NULL);
CREATE TABLE "ScoutingPresetVersion" ("id" TEXT NOT NULL PRIMARY KEY, "presetId" TEXT NOT NULL, "versionNumber" INTEGER NOT NULL, "schemaVersion" INTEGER NOT NULL, "configJson" TEXT NOT NULL, "configHash" TEXT NOT NULL, "changeReason" TEXT NOT NULL, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, "createdBySource" TEXT, CONSTRAINT "ScoutingPresetVersion_presetId_fkey" FOREIGN KEY ("presetId") REFERENCES "ScoutingPreset" ("id") ON DELETE RESTRICT ON UPDATE CASCADE);
CREATE TABLE "ActiveScoutingConfiguration" ("id" TEXT NOT NULL PRIMARY KEY DEFAULT 'default', "activePresetVersionId" TEXT NOT NULL, "updatedAt" DATETIME NOT NULL, CONSTRAINT "ActiveScoutingConfiguration_activePresetVersionId_fkey" FOREIGN KEY ("activePresetVersionId") REFERENCES "ScoutingPresetVersion" ("id") ON DELETE RESTRICT ON UPDATE CASCADE);
CREATE TABLE "Scout" ("id" TEXT NOT NULL PRIMARY KEY, "firstName" TEXT NOT NULL, "lastName" TEXT NOT NULL, "evaluatingRating" INTEGER NOT NULL, "potentialRating" INTEGER NOT NULL, "skaterRating" INTEGER NOT NULL, "goalieRating" INTEGER NOT NULL, "specialtiesJson" TEXT NOT NULL DEFAULT '[]', "countryFamiliarityJson" TEXT NOT NULL DEFAULT '{}', "positionFamiliarityJson" TEXT NOT NULL DEFAULT '{}', "persistentBias" REAL NOT NULL DEFAULT 0, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" DATETIME NOT NULL);
CREATE TABLE "ScoutingDepartment" ("id" TEXT NOT NULL PRIMARY KEY, "teamId" TEXT NOT NULL, "name" TEXT NOT NULL, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" DATETIME NOT NULL, CONSTRAINT "ScoutingDepartment_teamId_fkey" FOREIGN KEY ("teamId") REFERENCES "Team" ("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE TABLE "ScoutingDepartmentScout" ("id" TEXT NOT NULL PRIMARY KEY, "departmentId" TEXT NOT NULL, "scoutId" TEXT NOT NULL, "role" TEXT NOT NULL DEFAULT 'ASSISTANT', "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "ScoutingDepartmentScout_departmentId_fkey" FOREIGN KEY ("departmentId") REFERENCES "ScoutingDepartment" ("id") ON DELETE CASCADE ON UPDATE CASCADE, CONSTRAINT "ScoutingDepartmentScout_scoutId_fkey" FOREIGN KEY ("scoutId") REFERENCES "Scout" ("id") ON DELETE RESTRICT ON UPDATE CASCADE);
CREATE TABLE "TeamProspectKnowledge" ("id" TEXT NOT NULL PRIMARY KEY, "teamId" TEXT NOT NULL, "playerId" TEXT NOT NULL, "currentReportId" TEXT, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" DATETIME NOT NULL, CONSTRAINT "TeamProspectKnowledge_teamId_fkey" FOREIGN KEY ("teamId") REFERENCES "Team" ("id") ON DELETE CASCADE ON UPDATE CASCADE, CONSTRAINT "TeamProspectKnowledge_playerId_fkey" FOREIGN KEY ("playerId") REFERENCES "Player" ("id") ON DELETE RESTRICT ON UPDATE CASCADE);
CREATE TABLE "ScoutingAssignment" ("id" TEXT NOT NULL PRIMARY KEY, "teamId" TEXT NOT NULL, "targetType" TEXT NOT NULL, "targetJson" TEXT NOT NULL, "observedOn" TEXT NOT NULL, "durationDays" INTEGER NOT NULL, "seed" TEXT NOT NULL, "status" TEXT NOT NULL DEFAULT 'PREPARED', "configVersionId" TEXT NOT NULL, "configHash" TEXT NOT NULL, "completedAt" DATETIME, "cancelledAt" DATETIME, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" DATETIME NOT NULL, CONSTRAINT "ScoutingAssignment_teamId_fkey" FOREIGN KEY ("teamId") REFERENCES "Team" ("id") ON DELETE CASCADE ON UPDATE CASCADE, CONSTRAINT "ScoutingAssignment_configVersionId_fkey" FOREIGN KEY ("configVersionId") REFERENCES "ScoutingPresetVersion" ("id") ON DELETE RESTRICT ON UPDATE CASCADE);
CREATE TABLE "ScoutingAssignmentScout" ("id" TEXT NOT NULL PRIMARY KEY, "assignmentId" TEXT NOT NULL, "scoutId" TEXT NOT NULL, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "ScoutingAssignmentScout_assignmentId_fkey" FOREIGN KEY ("assignmentId") REFERENCES "ScoutingAssignment" ("id") ON DELETE CASCADE ON UPDATE CASCADE, CONSTRAINT "ScoutingAssignmentScout_scoutId_fkey" FOREIGN KEY ("scoutId") REFERENCES "Scout" ("id") ON DELETE RESTRICT ON UPDATE CASCADE);
CREATE TABLE "ScoutingObservation" ("id" TEXT NOT NULL PRIMARY KEY, "teamId" TEXT NOT NULL, "playerId" TEXT NOT NULL, "scoutId" TEXT NOT NULL, "assignmentId" TEXT NOT NULL, "observationId" TEXT NOT NULL, "observationJson" TEXT NOT NULL, "sourcePlayerStateHash" TEXT NOT NULL, "observedOn" TEXT NOT NULL, "durationDays" INTEGER NOT NULL, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "ScoutingObservation_teamId_fkey" FOREIGN KEY ("teamId") REFERENCES "Team" ("id") ON DELETE CASCADE ON UPDATE CASCADE, CONSTRAINT "ScoutingObservation_playerId_fkey" FOREIGN KEY ("playerId") REFERENCES "Player" ("id") ON DELETE RESTRICT ON UPDATE CASCADE, CONSTRAINT "ScoutingObservation_scoutId_fkey" FOREIGN KEY ("scoutId") REFERENCES "Scout" ("id") ON DELETE RESTRICT ON UPDATE CASCADE, CONSTRAINT "ScoutingObservation_assignmentId_fkey" FOREIGN KEY ("assignmentId") REFERENCES "ScoutingAssignment" ("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE TABLE "TeamScoutingReport" ("id" TEXT NOT NULL PRIMARY KEY, "knowledgeId" TEXT NOT NULL, "teamId" TEXT NOT NULL, "playerId" TEXT NOT NULL, "versionNumber" INTEGER NOT NULL, "reportJson" TEXT NOT NULL, "reportHash" TEXT NOT NULL, "sourcePlayerStateHash" TEXT NOT NULL, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "TeamScoutingReport_knowledgeId_fkey" FOREIGN KEY ("knowledgeId") REFERENCES "TeamProspectKnowledge" ("id") ON DELETE CASCADE ON UPDATE CASCADE, CONSTRAINT "TeamScoutingReport_teamId_fkey" FOREIGN KEY ("teamId") REFERENCES "Team" ("id") ON DELETE CASCADE ON UPDATE CASCADE, CONSTRAINT "TeamScoutingReport_playerId_fkey" FOREIGN KEY ("playerId") REFERENCES "Player" ("id") ON DELETE RESTRICT ON UPDATE CASCADE);
CREATE TABLE "TeamProspectWatchlistEntry" ("id" TEXT NOT NULL PRIMARY KEY, "teamId" TEXT NOT NULL, "playerId" TEXT NOT NULL, "manualPriority" INTEGER NOT NULL DEFAULT 0, "note" TEXT, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" DATETIME NOT NULL, CONSTRAINT "TeamProspectWatchlistEntry_teamId_fkey" FOREIGN KEY ("teamId") REFERENCES "Team" ("id") ON DELETE CASCADE ON UPDATE CASCADE, CONSTRAINT "TeamProspectWatchlistEntry_playerId_fkey" FOREIGN KEY ("playerId") REFERENCES "Player" ("id") ON DELETE RESTRICT ON UPDATE CASCADE);
CREATE UNIQUE INDEX "ScoutingPreset_name_key" ON "ScoutingPreset"("name");
CREATE UNIQUE INDEX "ScoutingPresetVersion_presetId_versionNumber_key" ON "ScoutingPresetVersion"("presetId", "versionNumber");
CREATE UNIQUE INDEX "ActiveScoutingConfiguration_activePresetVersionId_key" ON "ActiveScoutingConfiguration"("activePresetVersionId");
CREATE UNIQUE INDEX "ScoutingDepartment_teamId_key" ON "ScoutingDepartment"("teamId");
CREATE UNIQUE INDEX "ScoutingDepartmentScout_departmentId_scoutId_key" ON "ScoutingDepartmentScout"("departmentId", "scoutId");
CREATE UNIQUE INDEX "TeamProspectKnowledge_teamId_playerId_key" ON "TeamProspectKnowledge"("teamId", "playerId");
CREATE UNIQUE INDEX "ScoutingAssignmentScout_assignmentId_scoutId_key" ON "ScoutingAssignmentScout"("assignmentId", "scoutId");
CREATE UNIQUE INDEX "ScoutingObservation_observationId_key" ON "ScoutingObservation"("observationId");
CREATE UNIQUE INDEX "ScoutingObservation_assignmentId_scoutId_playerId_key" ON "ScoutingObservation"("assignmentId", "scoutId", "playerId");
CREATE UNIQUE INDEX "TeamScoutingReport_knowledgeId_versionNumber_key" ON "TeamScoutingReport"("knowledgeId", "versionNumber");
CREATE UNIQUE INDEX "TeamProspectWatchlistEntry_teamId_playerId_key" ON "TeamProspectWatchlistEntry"("teamId", "playerId");
CREATE INDEX "ScoutingAssignment_teamId_status_idx" ON "ScoutingAssignment"("teamId", "status");
CREATE INDEX "ScoutingObservation_teamId_playerId_idx" ON "ScoutingObservation"("teamId", "playerId");
CREATE INDEX "TeamScoutingReport_teamId_playerId_createdAt_idx" ON "TeamScoutingReport"("teamId", "playerId", "createdAt");
